script.text:
      /* <flatten type="Javascript"> */
function load$GridAIInvoice$(g) {g.add_commandEvent(on$GridAIInvoice$ExecuteCommand);}
function dispose$GridAIInvoice$(g) {try {g.remove_commandEvent(on$GridAIInvoice$ExecuteCommand);} catch (ex) {}}
function scatter$GridAIInvoice$(g) {reset$GridAIInvoice(g);}
function on$GridAIInvoice$ExecuteCommand(sender, e) {
  var action = e.type.Action, g = sender, id = g.get_id(), f = g.get_element().parentForm;
  switch (action) {
    case 'Cancel':
      if (f._action == 'View' || !f.getItemValue('stt_rec_hd')) break;
      var msg = (g._language == 'v' ? 'Bạn có chắc chắn bỏ hóa đơn đã chọn không?' : 'Are you sure you want to remove selected invoice?');
      $message.show(msg, 0, String.format('run$GridAIInvoice($find(\'{0}\'));', id), String.format('$find(\'{0}\')._focusWhenTabChanged();', id));
      break;
    default:
      break;
  }
}
function run$GridAIInvoice(g) {
  var f = g.get_element().parentForm;
  f.setItemValues('stt_rec_hd, ma_ct_hd, ma_kh_hd, so_ct_hd, so_seri_hd, ngay_ct_hd', ['', '', '', '', null]);
  g._rows = [];
  g._rowCount = 0;
  g._render();
  reset$GridAIInvoice(g);
}
function reset$GridAIInvoice(g) {
  var o = g.get_toolbarButton('Search');
  if (!o._$addHandler) {
    o.onclick = function() {
      if (!g.get_element().parentForm.validFields('ngay_lct, ma_kh')) return false;
      g.executeCommand({commandName:'Search', commandArgument:'0'});
    }
    o._$addHandler = true;
  }
}
/* </flatten> */

query.text:
declare @vcID char(13), @vcCode char(3) select @vcID = stt_rec_hd, @vcCode = ma_ct_hd from hddc where stt_rec = @stt_rec &Struct;
if @@copying = 0 and @vcCode <> '' begin
&d;
declare @c varchar(64) if @vcCode = 'HDA' select @c = 'c81$000000', @m = 'm81$', @d = 'd81$' else if @vcCode = 'HD1' select @c = 'c21$000000', @m = 'm21$', @d = 'd21$', @join = '', @f1 = 'a.dien_giai', @f2 = 'a.gia_nt, a.tien_nt2, a.gia, a.tien2' else if @vcCode = 'HD2' select @c = 'c22$000000', @m = 'm22$', @d = 'd22$', @join = '', @f1 = 'a.dien_giai', @f2 = 'a.gia_nt, a.tien_nt2, a.gia, a.tien2' else if @vcCode = 'HD4' select @c = 'c25$000000', @m = 'm25$', @d = 'd25$' else if @vcCode = 'HD5' select @m = 'hddc', @d = 'cthddc', @join = '', @f1 = 'a.dien_giai', @f2 = 'a.gia_nt, a.tien_nt2, a.gia, a.tien2' else if @vcCode = 'PXC' select @c = 'c86$000000', @m = 'm86$', @d = 'd86$', @f2 = 'a.gia_nt, a.tien_nt, a.gia, a.tien' else if @vcCode = 'PXD' select @m = 'm26$000000', @d = 'd26$000000', @join = '', @f1 = 'a.dien_giai', @f2 = 'a.gia_nt, a.tien_nt, a.gia, a.tien' else if @vcCode = 'HD6' select @c = 'm42$000000', @m = 'm42$000000', @d = 'd42$000000', @join = '', @f1 = 'a.dien_giai', @f2 = 'a.gia_nt, a.tien_nt2, a.gia, a.tien2'
if @vcCode in ('HDA', 'HD1', 'HD2', 'HD4', 'PXC') begin select @q = 'select @x = convert(char(6), ngay_ct, 112) from ' + @c + ' where stt_rec = ''' + replace(@vcID, '''', '''''') + '''' exec sp_executesql @q, N'@x char(6) output', @x = @p output select @m = @m + @p, @d = @d + @p end &q; end else select top 0 @@fieldExternal from #r

&d;
select @p = convert(char(6), @vcDate, 112)
if @vcCode = 'HDA' select @d = 'd81$' + @p, @m = 'm81$' + @p else if @vcCode = 'HD1' select @d = 'd21$' + @p, @m = 'm21$' + @p, @join = '', @f1 = 'a.dien_giai', @f2 = 'a.gia_nt, a.tien_nt2, a.gia, a.tien2' else if @vcCode = 'HD2' select @d = 'd22$' + @p, @m = 'm22$' + @p, @join = '', @f1 = 'a.dien_giai', @f2 = 'a.gia_nt, a.tien_nt2, a.gia, a.tien2' else if @vcCode = 'HD4' select @d = 'd25$' + @p, @m = 'm25$' + @p else if @vcCode = 'HD5' select @d = 'cthddc', @m = 'hddc', @join = '', @f1 = 'a.dien_giai', @f2 = 'a.gia_nt, a.tien_nt2, a.gia, a.tien2' else if @vcCode = 'PXC' select @d = 'd86$' + @p, @m = 'm86$' + @p, @f2 = 'a.gia_nt, a.tien_nt, a.gia, a.tien' else if @vcCode = 'PXD' select @d = 'd26$000000', @m = 'm26$000000', @join = '', @f1 = 'a.dien_giai', @f2 = 'a.gia_nt, a.tien_nt, a.gia, a.tien' else if @vcCode = 'HD6' select @d = 'd42$000000', @m = 'm42$000000', @join = '', @f1 = 'a.dien_giai', @f2 = 'a.gia_nt, a.tien_nt2, a.gia, a.tien2'
&Struct; &q;
